/**
 * Haiti medication catalog for Medora-S Phase 1.
 * Stable codes: preserve existing codes for inventory-linked items; derive rest from genericName + strength + dosageForm + route.
 * Offline-first: searchText and aliases support local autocomplete and label rendering.
 */

export type HaitiMedicationSeed = {
  code?: string;
  genericName: string;
  displayNameFr: string;
  strength: string;
  dosageForm: string;
  route: string;
  therapeuticClass: string;
  commonAliases: string[];
  isEssential: boolean;
  isActive: boolean;
  sortPriority: number;
};

